import { useTranslation } from "react-i18next";

import { FONT_SCALES, useSettingsStore, type Theme } from "../../stores/settingsStore";
import type { SupportedLanguage } from "../../i18n";

export function AppearancePanel() {
  const { t } = useTranslation("settings");
  const { theme, language, fontScale, setTheme, setLanguage, setFontScale } = useSettingsStore();

  return (
    <section
      className="rounded-[var(--radius-lg)] border p-5"
      style={{ borderColor: "var(--color-border)", backgroundColor: "var(--color-surface)" }}
    >
      <h2 className="mb-4 font-[var(--font-display)] text-lg">{t("sections.appearance")}</h2>

      <div className="flex flex-col gap-4 sm:flex-row sm:gap-10">
        <div>
          <span className="mb-2 block text-xs font-medium uppercase tracking-wide" style={{ color: "var(--color-text-faint)" }}>
            {t("appearance.language")}
          </span>
          <div className="inline-flex overflow-hidden rounded-[var(--radius-sm)] border" style={{ borderColor: "var(--color-border-strong)" }}>
            {(["cs", "en"] as SupportedLanguage[]).map((lang) => (
              <button
                key={lang}
                type="button"
                onClick={() => void setLanguage(lang)}
                aria-pressed={language === lang}
                className="px-3 py-1.5 text-sm transition-colors"
                style={{
                  backgroundColor: language === lang ? "var(--color-accent)" : "transparent",
                  color: language === lang ? "var(--color-accent-contrast)" : "var(--color-text-muted)",
                }}
              >
                {lang === "cs" ? t("appearance.languageCs") : t("appearance.languageEn")}
              </button>
            ))}
          </div>
        </div>

        <div>
          <span className="mb-2 block text-xs font-medium uppercase tracking-wide" style={{ color: "var(--color-text-faint)" }}>
            {t("appearance.theme")}
          </span>
          <div className="inline-flex overflow-hidden rounded-[var(--radius-sm)] border" style={{ borderColor: "var(--color-border-strong)" }}>
            {(["dark", "light"] as Theme[]).map((th) => (
              <button
                key={th}
                type="button"
                onClick={() => void setTheme(th)}
                aria-pressed={theme === th}
                className="px-3 py-1.5 text-sm transition-colors"
                style={{
                  backgroundColor: theme === th ? "var(--color-accent)" : "transparent",
                  color: theme === th ? "var(--color-accent-contrast)" : "var(--color-text-muted)",
                }}
              >
                {th === "dark" ? t("appearance.themeDark") : t("appearance.themeLight")}
              </button>
            ))}
          </div>
        </div>

        <div>
          <span className="mb-2 block text-xs font-medium uppercase tracking-wide" style={{ color: "var(--color-text-faint)" }}>
            {t("appearance.fontSize")}
          </span>
          <div className="inline-flex overflow-hidden rounded-[var(--radius-sm)] border" style={{ borderColor: "var(--color-border-strong)" }}>
            {FONT_SCALES.map((scale) => (
              <button
                key={scale}
                type="button"
                onClick={() => void setFontScale(scale)}
                aria-pressed={fontScale === scale}
                title={`${scale} %`}
                className="px-3 py-1.5 transition-colors"
                style={{
                  // Preview each step at its own size; sized in px on purpose
                  // so the labels don't rescale when the root font changes.
                  fontSize: `${(14 * scale) / 100}px`,
                  backgroundColor: fontScale === scale ? "var(--color-accent)" : "transparent",
                  color: fontScale === scale ? "var(--color-accent-contrast)" : "var(--color-text-muted)",
                }}
              >
                A
              </button>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}

import { create } from "zustand";

import i18n, { type SupportedLanguage } from "../i18n";
import { getSetting, setSetting } from "../db/repositories/settingsRepo";

export type Theme = "dark" | "light";

/** Root font-size scale in % — everything is sized in rem, so this scales
 * the whole UI. Keep the steps modest so layouts don't break. */
export const FONT_SCALES = [87.5, 100, 112.5, 125, 150, 175, 200] as const;
export type FontScale = (typeof FONT_SCALES)[number];
const DEFAULT_FONT_SCALE: FontScale = 100;

interface SettingsState {
  theme: Theme;
  language: SupportedLanguage;
  fontScale: FontScale;
  hydrated: boolean;
  hydrate: () => Promise<void>;
  setTheme: (theme: Theme) => Promise<void>;
  setLanguage: (language: SupportedLanguage) => Promise<void>;
  setFontScale: (scale: FontScale) => Promise<void>;
}

function applyTheme(theme: Theme) {
  const root = document.documentElement;
  root.classList.remove("dark", "light");
  root.classList.add(theme);
}

function applyFontScale(scale: FontScale) {
  document.documentElement.style.fontSize = scale === 100 ? "" : `${scale}%`;
}

function parseFontScale(raw: string | null): FontScale {
  const value = Number(raw);
  return (FONT_SCALES as readonly number[]).includes(value)
    ? (value as FontScale)
    : DEFAULT_FONT_SCALE;
}

export const useSettingsStore = create<SettingsState>((set) => ({
  theme: "dark",
  language: "cs",
  fontScale: DEFAULT_FONT_SCALE,
  hydrated: false,

  hydrate: async () => {
    const [storedTheme, storedLanguage, storedFontScale] = await Promise.all([
      getSetting("theme"),
      getSetting("language"),
      getSetting("font_scale"),
    ]);
    const theme: Theme = storedTheme === "light" ? "light" : "dark";
    const language: SupportedLanguage = storedLanguage === "en" ? "en" : "cs";
    const fontScale = parseFontScale(storedFontScale);

    applyTheme(theme);
    applyFontScale(fontScale);
    await i18n.changeLanguage(language);

    set({ theme, language, fontScale, hydrated: true });
  },

  setTheme: async (theme) => {
    applyTheme(theme);
    set({ theme });
    await setSetting("theme", theme);
  },

  setLanguage: async (language) => {
    await i18n.changeLanguage(language);
    set({ language });
    await setSetting("language", language);
  },

  setFontScale: async (fontScale) => {
    applyFontScale(fontScale);
    set({ fontScale });
    await setSetting("font_scale", String(fontScale));
  },
}));

// Apply a sane default immediately so the very first paint (before the DB
// hydration resolves) is already dark-themed, per the "dark by default"
// requirement.
applyTheme(useSettingsStore.getState().theme);

